async def load_all_lessons():
    total = 0
    for course_id, lessons in ALL_LESSONS.items():
        result = await courses_collection.update_one(
            {"id": course_id},
            {"$set": {"lessons": lessons, "lessonsCount": len(lessons)}}
        )
        if result.modified_count > 0:
            print(f"Updated {course_id}: {len(lessons)} lessons")
            total += 1
        else:
            print(f"WARNING: {course_id} not found or not modified!")
    print(f"\nDone! Updated {total} courses.")

asyncio.run(load_all_lessons())
